import React, { useState, useRef, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';

const CubeInput = () => {
  const navigate = useNavigate();
  
  const [cubeState, setCubeState] = useState({
    U: Array(9).fill('white'),
    D: Array(9).fill('yellow'),
    L: Array(9).fill('orange'),
    R: Array(9).fill('red'),
    F: Array(9).fill('green'),
    B: Array(9).fill('blue')
  });

  const [loading, setLoading] = useState(false);
  const [openPicker, setOpenPicker] = useState({ face: null, index: null });
  const pickerRef = useRef(null);

  const colorOptions = ['white', 'yellow', 'orange', 'red', 'green', 'blue'];

  const colorMap = {
    white: '#ffffff',
    yellow: '#ffff00',
    orange: '#ffa500',
    red: '#ff0000',
    green: '#00ff00',
    blue: '#0000ff'
  };

  useEffect(() => {
    const handleClickOutside = (event) => {
      if (pickerRef.current && !pickerRef.current.contains(event.target)) {
        setOpenPicker({ face: null, index: null });
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const handleStickerClick = (face, index) => {
    if (openPicker.face === face && openPicker.index === index) {
      setOpenPicker({ face: null, index: null });
    } else {
      setOpenPicker({ face, index });
    }
  };

  const handleColorChange = (face, index, color) => {
    const newCubeState = { ...cubeState };
    newCubeState[face][index] = color;
    setCubeState(newCubeState);
    setOpenPicker({ face: null, index: null });
  };

  const handleSubmit = async () => {
    setLoading(true);
    try {
      const response = await axios.post('http://localhost:8000/api/solve/', cubeState);
      console.log('Solution:', response.data);
      navigate('/solve', { state: { solution: response.data.solution, cubeState: cubeState } });
    } catch (error) {
      console.error('Error:', error);
      alert('Failed to solve cube. Please check your colors.');
    } finally {
      setLoading(false);
    }
  };

  const renderSticker = (face, index, color) => {
    const isOpen = openPicker.face === face && openPicker.index === index;
    
    return (
      <div style={{ position: 'relative', display: 'inline-block' }} ref={isOpen ? pickerRef : null}>
        <div
          onClick={() => handleStickerClick(face, index)}
          style={{
            width: '50px',
            height: '50px',
            backgroundColor: colorMap[color],
            border: '1px solid black',
            margin: '2px',
            cursor: 'pointer'
          }}
        />
        {isOpen && (
          <div style={{
            position: 'absolute',
            top: '55px',
            left: '0',
            backgroundColor: 'white',
            border: '1px solid #434343',
            borderRadius: '4px',
            zIndex: 100,
            display: 'flex',
            flexDirection: 'column'
          }}>
            {colorOptions.map((c) => (
              <div
                key={c}
                onClick={() => handleColorChange(face, index, c)}
                style={{
                  width: '50px',
                  height: '50px',
                  backgroundColor: colorMap[c],
                  border: '1px solid #434343',
                  cursor: 'pointer'
                }}
                onMouseEnter={(e) => e.target.style.border = '2px solid black'}
                onMouseLeave={(e) => e.target.style.border = '1px solid #434343'}
              />
            ))}
          </div>
        )}
      </div>
    );
  };

  const renderFace = (faceName, faceColors) => {
    const faceLabels = { U: 'UP', D: 'DOWN', L: 'LEFT', R: 'RIGHT', F: 'FRONT', B: 'BACK' };
    return (
      <div style={{ margin: '20px', display: 'inline-block' }}>
        <h3>{faceLabels[faceName]}</h3>
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)' }}>
          {faceColors.map((color, idx) => renderSticker(faceName, idx, color))}
        </div>
      </div>
    );
  };

  return (
    <div className="cube-input">
      <button className="back-btn montserrat-alternates-regular" onClick={() => navigate('/')}>
        ← Back
      </button>
      <h2 className="montserrat-alternates-semibold">Select Cube Colors</h2>
      <div style={{ display: 'flex', flexWrap: 'wrap', justifyContent: 'center' }}>
        {Object.keys(cubeState).map((face) => renderFace(face, cubeState[face]))}
      </div>
      <button className="submit-btn montserrat-alternates-bold" onClick={handleSubmit} disabled={loading}>
        {loading ? 'Solving...' : 'Solve Cube'}
      </button>
    </div>
  );
};

export default CubeInput;
